function debounceCallC(calls: number[], gapMs: number): number[] {
  const fired: number[] = [];
  let last = -Infinity;
  for (let i = 0; i < calls.length; i++) {
    const t = calls[i];
    const isLast = i === calls.length - 1;
    const nextGap = isLast ? Infinity : calls[i + 1] - t;
    if (t - last >= gapMs || nextGap >= gapMs) {
      fired.push(t);
      last = t;
    }
  }
  return fired;
}

