function isPalindromeC(text: string): boolean {
  const cleaned = text.toLowerCase().replace(/[^a-z0-9]/g, '');
  let lo = 0;
  let hi = cleaned.length - 1;
  while (lo < hi) {
    if (cleaned[lo] !== cleaned[hi]) {
      return false;
    }
    lo++;
    hi--;
  }
  return true;
}

